final:
module RefModule (
    input wire clk,
    input wire rst,
    output reg [3:0] gray
    );

reg [3:0] unused_binary_count;

always @(posedge clk) begin
    if (rst) begin
        unused_binary_count <= 4'b0000;
    end else begin
        unused_binary_count <= unused_binary_count + 1;
    end
end

always @(*) begin
    gray = (unused_binary_count >> 1) ^ unused_binary_count;
end

endmodule
